function parseRecord(text) {
  const trimmed = text.trim();
  if (trimmed.length === 0) {
    return null;
  }
  return JSON.parse(trimmed);
}

export class JsonSequenceParser {
  #pending = "";

  push(bytes) {
    this.#pending += Buffer.from(bytes).toString("utf8");
    const sections = this.#pending.split("\x1e");
    this.#pending = sections.pop();

    const records = [];
    for (const section of sections) {
      const record = parseRecord(section);
      if (record !== null) {
        records.push(record);
      }
    }
    return records;
  }

  finish() {
    const record = parseRecord(this.#pending);
    this.#pending = "";
    return record === null ? [] : [record];
  }
}

