export class FragmentAssembler {
  #documents = new Map();
  #lastSequence = -1;

  apply(fragment) {
    if (typeof fragment.channel !== "string" || !Number.isInteger(fragment.sequence)) {
      throw new TypeError("invalid audit fragment");
    }
    if (fragment.sequence <= this.#lastSequence) {
      return { kind: "duplicate", channel: fragment.channel };
    }
    if (fragment.sequence !== this.#lastSequence + 1) {
      throw new Error("sequence gap for " + fragment.channel);
    }

    const previous = this.#documents.get(fragment.channel) ?? "";
    this.#documents.set(fragment.channel, previous + String(fragment.text ?? ""));
    this.#lastSequence = fragment.sequence;
    return { kind: "applied", channel: fragment.channel };
  }

  snapshot() {
    return Object.fromEntries([...this.#documents.entries()].sort(([left], [right]) => left.localeCompare(right)));
  }
}

