import { JsonSequenceParser } from "./json-sequence-parser.mjs";
import { FragmentAssembler } from "./fragment-assembler.mjs";

export async function readAuditExport(chunks) {
  const parser = new JsonSequenceParser();
  const assembler = new FragmentAssembler();

  for await (const chunk of chunks) {
    for (const fragment of parser.push(chunk)) {
      assembler.apply(fragment);
    }
  }

  for (const fragment of parser.finish()) {
    assembler.apply(fragment);
  }

  return assembler.snapshot();
}

