import test from "node:test";
import assert from "node:assert/strict";

import { readAuditExport } from "../src/audit-export-reader.mjs";

function wire(records) {
  return Buffer.from(records.map((record) => "\x1e" + JSON.stringify(record) + "\n").join(""), "utf8");
}

test("single-channel ASCII fragments assemble across frame boundaries", async () => {
  const bytes = wire([
    { channel: "acct-7", sequence: 0, text: "alpha " },
    { channel: "acct-7", sequence: 1, text: "beta" }
  ]);
  const marker = bytes.indexOf(Buffer.from("\x1e", "utf8"), 1);
  const result = await readAuditExport([bytes.subarray(0, marker), bytes.subarray(marker)]);
  assert.deepEqual(result, { "acct-7": "alpha beta" });
});

test("same-channel retransmission is idempotent", async () => {
  const result = await readAuditExport([wire([
    { channel: "acct-2", sequence: 0, text: "A" },
    { channel: "acct-2", sequence: 0, text: "A" },
    { channel: "acct-2", sequence: 1, text: "B" }
  ])]);
  assert.deepEqual(result, { "acct-2": "AB" });
});

test("a forward sequence gap is rejected", async () => {
  const bytes = wire([{ channel: "acct-9", sequence: 2, text: "late" }]);
  await assert.rejects(readAuditExport([bytes]), /sequence gap/);
});
